<template><section v-if="open" class="bottom-recipe"><div class="legacy-window"><div class="legacy-titlebar"><strong>{{ titleBase }}</strong><span v-if="emphasizeText">for {{ emphasizeText }}</span><input :value="findModel" @input="emit('update:findModel',($event.target as HTMLInputElement).value)" @keydown.enter="emit('apply-find')"/><button @click="emit('apply-find')">🔍</button><button @click="emit('close')">Hide</button></div><div class="recipe-scroll"><div v-for="col in recipeCols" :key="col[0]?.id"><div v-for="r in col" :key="r.id" class="list-li" :class="{active:selectedRecipeIds.includes(r.id)}" @click="emit('pick',{recipeId:r.id,event:$event})" @contextmenu.prevent="emit('item-contextmenu',{recipeId:r.id,event:$event})">{{ r.name }}</div></div></div><div class="grid-wrap" v-if="selectedRecipeSingle"><table v-if="selectedRecipeSingle.columns.length"><thead><tr><th v-for="c in selectedRecipeSingle.columns" :key="c">{{ c }}</th></tr></thead><tbody><tr v-for="(row,i) in selectedRecipeSingle.rows" :key="i"><td v-for="c in selectedRecipeSingle.columns" :key="c">{{ row[c] }}</td></tr></tbody></table><div v-else>Preview not available for this file type.</div></div></div></section></template>
<script setup lang="ts">import type { PropType } from 'vue'; import type { RecipeDetail } from '../api/recipeTestApi'; defineProps({open:Boolean,activePlaten:Number,findModel:String,findClass:String,recipeCols:{type:Array as PropType<RecipeDetail[][]>,default:()=>[]},selectedRecipeIds:{type:Array as PropType<string[]>,default:()=>[]},selectedRecipeSingle:{type:Object as PropType<RecipeDetail|null>,default:null},titleBase:String,emphasizeText:String,editMode:Boolean,listMode:String,scrollLeft:Number,colWidths:Object}); const emit=defineEmits(['activate','area-click','open-menu','update:findModel','apply-find','close','pick','item-contextmenu','register-item-ref','register-root','update:listMode','body-scroll','start-resize','register-scroll-el'])</script>
<style scoped>.bottom-recipe{padding-bottom:80px}.legacy-window{background:#c0c0c0;border:1px solid #8d8d8d;padding:8px}.legacy-titlebar{display:flex;gap:8px;align-items:center;background:#d4d0c8;padding:6px}.recipe-scroll{display:flex;gap:8px;overflow:auto;background:#fff;border:1px solid #8d8d8d;padding:8px;height:180px}.list-li{font-weight:700;cursor:pointer}.list-li.active{background:#0a246a;color:#fff}.grid-wrap{background:#fff;border:1px solid #8d8d8d;margin-top:8px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #aaa;padding:4px}</style>
